#print(strings)
def circularlyUnique(strings):
    trackedStrings = strings
    uniqueStrings = []
    for string in trackedStrings:
        currentString = string
        allForms = []
        for indices in range(len(string) - 1):
            allForms.append(string[indices:] + string[:indices])
            for otherString in trackedStrings:
                if otherString in allForms:
                    trackedStrings.remove(otherString)
        uniqueStrings.append(currentString)
    return uniqueStrings, len(uniqueStrings)

